-- Generated by scripts/parse-event-scrape.mjs from public event pages and screenshots.
-- Review source screenshots/text under output/event-scrape before production use.
alter table public.events add column if not exists details text not null default '';

on conflict (id) do update set
  name = excluded.name,
  area = excluded.area,
  has_daytime = excluded.has_daytime,
  has_night = excluded.has_night,
  opening_hour_day = excluded.opening_hour_day,
  opening_hour_night = excluded.opening_hour_night,
  pr_structure = excluded.pr_structure,
  trust_seed = excluded.trust_seed;

on conflict (id) do update set
  store_id = excluded.store_id,
  date_label = excluded.date_label,
  weekday = excluded.weekday,
  starts_at = excluded.starts_at,
  session = excluded.session,
  category = excluded.category,
  title = excluded.title,
  details = excluded.details,
  source_url = excluded.source_url;
